  LUA_SHIM_OK(0),
  LUA_SHIM_YIELD(1),
  LUA_SHIM_ERRRUN(2),
  LUA_SHIM_ERRSYNTAX(3),
  LUA_SHIM_ERRMEM(4),
  LUA_SHIM_ERRGCMM(5),
  LUA_SHIM_ERRERR(6);

  final int value;
  const lua_shim_status(this.value);

  static lua_shim_status fromValue(int value) => switch (value) {
    0 => LUA_SHIM_OK,
    1 => LUA_SHIM_YIELD,
    2 => LUA_SHIM_ERRRUN,
    3 => LUA_SHIM_ERRSYNTAX,
    4 => LUA_SHIM_ERRMEM,
    5 => LUA_SHIM_ERRGCMM,
    6 => LUA_SHIM_ERRERR,
    _ => throw ArgumentError('Unknown value for lua_shim_status: $value'),
  };
}

