    2 => LUA_SHIM_OPMUL,
    3 => LUA_SHIM_OPMOD,
    4 => LUA_SHIM_OPPOW,
    5 => LUA_SHIM_OPDIV,
    6 => LUA_SHIM_OPIDIV,
    7 => LUA_SHIM_OPBAND,
    8 => LUA_SHIM_OPBOR,
    9 => LUA_SHIM_OPBXOR,
    10 => LUA_SHIM_OPSHL,
    11 => LUA_SHIM_OPSHR,
    12 => LUA_SHIM_OPUNM,
    13 => LUA_SHIM_OPBNOT,
    _ => throw ArgumentError('Unknown value for lua_shim_arith: $value'),
  };
}

/// 比较操作枚举。
///
/// 对应 LUA_OPEQ / LUA_OPLT / LUA_OPLE。
/// 用于 lua_shim_compare() 的 op 参数。
enum lua_shim_compare {
  LUA_SHIM_OPEQ(0),
  LUA_SHIM_OPLT(1),
  LUA_SHIM_OPLE(2);

  final int value;
  const lua_shim_compare(this.value);

  static lua_shim_compare fromValue(int value) => switch (value) {
    0 => LUA_SHIM_OPEQ,
    1 => LUA_SHIM_OPLT,
    2 => LUA_SHIM_OPLE,
    _ => throw ArgumentError('Unknown value for lua_shim_compare: $value'),
  };
}

final class lua_State extends ffi.Opaque {}

/// 无标签的值 Union。调用方需自行保证读取的分支与 Lua 栈实际类型一致。
final class lua_shim_value extends ffi.Union {
  @ffi.Double()
  external double number;

  @ffi.Int64()
  external int integer;

  @ffi.Bool()
  external bool boolean;

  external ffi.Pointer<ffi.Char> string;

  @ffi.Size()
  external int length;

  external ffi.Pointer<ffi.Void> pointer;

  external ffi.Pointer<lua_State> thread;
}

typedef lua_shim_value_t = lua_shim_value;

/// 带标签的值容器。status 表示操作结果，type + value 表示值内容。
final class lua_shim_result extends ffi.Struct {
  /// < 操作状态（OK / 错误码）
  @ffi.UnsignedInt()
  external int statusAsInt;

  lua_shim_status get status => lua_shim_status.fromValue(statusAsInt);

  /// < 值类型标签
  @ffi.Int()
  external int typeAsInt;

  lua_shim_type get type => lua_shim_type.fromValue(typeAsInt);

  /// < 值内容
  external lua_shim_value_t value;
}

typedef lua_shim_result_t = lua_shim_result;

/// 通用结果类型
typedef const_char_ptr = ffi.Pointer<ffi.Char>;
typedef dart_lua_shim_never = ffi.Int;
typedef Dartdart_lua_shim_never = int;

final class dart_lua_shim_never_const_char_ptr_result extends ffi.Struct {
  @dart_lua_shim_never()
  external int value;

  external const_char_ptr error;
}

typedef dart_lua_shim_void_result_t = dart_lua_shim_never_const_char_ptr_result;

final class int_const_char_ptr_result extends ffi.Struct {
  @ffi.Int()
  external int value;

  external const_char_ptr error;
}

typedef dart_lua_shim_int_result_t = int_const_char_ptr_result;
typedef DartCFunctionFunction = ffi.Int Function(ffi.Pointer<lua_State> L);
typedef DartDartCFunctionFunction = int Function(ffi.Pointer<lua_State> L);
typedef DartCFunction = ffi.Pointer<ffi.NativeFunction<DartCFunctionFunction>>;
